import{_ as a,o as e,c as s,a7 as d}from"./chunks/framework.BEkMkAR4.js";const u=JSON.parse('{"title":"工具类目录文件总览","description":"","frontmatter":{},"headers":[],"relativePath":"DevelopmentDoc/CoreSDK/Utils/util.md","filePath":"DevelopmentDoc/CoreSDK/Utils/util.md"}'),l={name:"DevelopmentDoc/CoreSDK/Utils/util.md"};function n(i,t,o,r,p,h){return e(),s("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1774690858000"},[...t[0]||(t[0]=[d(`<h1 id="工具类目录文件总览" tabindex="-1">工具类目录文件总览 <a class="header-anchor" href="#工具类目录文件总览" aria-label="Permalink to &quot;工具类目录文件总览&quot;">​</a></h1><h2 id="目录结构" tabindex="-1">目录结构 <a class="header-anchor" href="#目录结构" aria-label="Permalink to &quot;目录结构&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>utils/</span></span>
<span class="line"><span>├── index.js              # 通用前端工具（保留业务函数 + re-export lodash-es）</span></span>
<span class="line"><span>├── aes.js                # 加解密（需改造公私钥注入方式）</span></span>
<span class="line"><span>├── auth.js               # Token 管理（基座内部）</span></span>
<span class="line"><span>├── dict.js               # 字典 Composable（基座内部，可对外）</span></span>
<span class="line"><span>├── dynamicTitle.js       # 动态标题（基座内部）</span></span>
<span class="line"><span>├── errorCode.js          # 错误码（可改造为可配置后对外）</span></span>
<span class="line"><span>├── eventBus.js           # 事件总线（通用，可对外）</span></span>
<span class="line"><span>├── gpsToAmap.js          # GPS 坐标转换（通用，可对外）</span></span>
<span class="line"><span>├── htmlToPdf.js          # HTML 转 PDF（通用，可对外）</span></span>
<span class="line"><span>├── loadPackage.js        # 子包懒加载（基座内部）</span></span>
<span class="line"><span>├── reg.js                # 正则集合（通用，可对外）</span></span>
<span class="line"><span>├── request.js            # HTTP 请求封装（基座内部）</span></span>
<span class="line"><span>├── ruoyi.js              # 若依工具函数（基座内部，部分可提炼）</span></span>
<span class="line"><span>├── theme.js              # 主题切换（通用，可对外）</span></span>
<span class="line"><span>├── tourLauncher.js       # 新手引导（基座内部）</span></span>
<span class="line"><span>├── upVersion.js          # 版本检测（通用，可对外）</span></span>
<span class="line"><span>├── useWebSocketV2.js     # WebSocket（通用，可对外）</span></span>
<span class="line"><span>├── validate.js           # 校验函数（通用，可对外）</span></span>
<span class="line"><span>├── grhtml5-6.8-min.js    # GridReport 第三方库（不对外）</span></span>
<span class="line"><span>└── grwebapp.js           # GridReport 报表通信（不对外）</span></span></code></pre></div><h2 id="目录定位" tabindex="-1">目录定位 <a class="header-anchor" href="#目录定位" aria-label="Permalink to &quot;目录定位&quot;">​</a></h2><p>utils 目录承担两类职责：</p><ol><li>提供可复用的前端通用能力，比如时间格式化、对象处理、WebSocket、事件总线、主题色处理、文件名解析等。</li><li>承载基座运行时所需的内部能力，比如 Token 管理、请求拦截、动态装载子包、字典读取、页面标题设置等。</li></ol><blockquote><p>开发时要先区分文件类型，再决定是否复用、是否对外暴露、往什么文件放。</p></blockquote><h2 id="分类总览" tabindex="-1">分类总览 <a class="header-anchor" href="#分类总览" aria-label="Permalink to &quot;分类总览&quot;">​</a></h2><h3 id="_1-对外通用工具" tabindex="-1">1. 对外通用工具 <a class="header-anchor" href="#_1-对外通用工具" aria-label="Permalink to &quot;1. 对外通用工具&quot;">​</a></h3><blockquote><p>这类文件耦合低，适合被业务项目直接复用，或者后续从 core-sdk 中统一导出。</p></blockquote><table tabindex="0"><thead><tr><th>文件</th><th>说明</th><th>适用场景</th></tr></thead><tbody><tr><td>index.js</td><td>通用前端方法集合，包含时间、URL、集合、表单配置、文件名处理等</td><td>常规业务开发</td></tr><tr><td>aes.js</td><td>RSA + DES 加解密封装</td><td>与后端约定加密传输</td></tr><tr><td>eventBus.js</td><td>轻量事件总线</td><td>非父子组件通信、跨模块通知</td></tr><tr><td>gpsToAmap.js</td><td>GPS 坐标转高德坐标</td><td>地图定位、轨迹展示</td></tr><tr><td>htmlToPdf.js</td><td>页面局部区域导出 PDF</td><td>打印、导出报表</td></tr><tr><td>dict.js</td><td>字典数据读取 composable</td><td>页面字典缓存、下拉字典回显</td></tr><tr><td>reg.js</td><td>常用业务正则集合</td><td>表单规则、数据校验</td></tr><tr><td>theme.js</td><td>Element Plus 主题色动态切换</td><td>主题定制</td></tr><tr><td>upVersion.js</td><td>基于 ETag 的前端版本更新提示</td><td>检测新版本并提醒刷新</td></tr><tr><td>useWebSocketV2.js</td><td>Vue 3 WebSocket 封装</td><td>实时消息、状态推送</td></tr><tr><td>validate.js</td><td>常规校验函数</td><td>URL、邮箱、数组等基础校验</td></tr><tr><td>errorCode.js</td><td>常见错误码文案映射</td><td>接口错误提示兜底</td></tr></tbody></table><h3 id="_2-基座内部能力" tabindex="-1">2. 基座内部能力 <a class="header-anchor" href="#_2-基座内部能力" aria-label="Permalink to &quot;2. 基座内部能力&quot;">​</a></h3><blockquote><p>这类文件对 store、router、内部 API、内部组件协议存在依赖，不建议业务项目直接复用。</p></blockquote><table tabindex="0"><thead><tr><th>文件</th><th>说明</th><th>原因</th></tr></thead><tbody><tr><td>auth.js</td><td>Token 的 Cookie 与 sessionStorage 管理</td><td>强绑定基座登录约定</td></tr><tr><td>dynamicTitle.js</td><td>动态设置系统标题</td><td>依赖 sysGlobal store</td></tr><tr><td>loadPackage.js</td><td>动态装载 form、etable、vtable、workbench</td><td>基座路由与插件初始化逻辑</td></tr><tr><td>request.js</td><td>axios 请求封装</td><td>深度耦合内部协议、鉴权、加密、下载</td></tr><tr><td>ruoyi.js</td><td>若依风格工具集</td><td>含历史兼容逻辑，建议按需提炼</td></tr><tr><td>tourLauncher.js</td><td>新手引导启动器</td><td>依赖具体布局组件实例</td></tr></tbody></table><h3 id="_3-第三方或历史兼容文件" tabindex="-1">3. 第三方或历史兼容文件 <a class="header-anchor" href="#_3-第三方或历史兼容文件" aria-label="Permalink to &quot;3. 第三方或历史兼容文件&quot;">​</a></h3><blockquote><p>这类文件以兼容接入为主，不建议继续扩展新功能。</p></blockquote><table tabindex="0"><thead><tr><th>文件</th><th>说明</th></tr></thead><tbody><tr><td>grhtml5-6.8-min.js</td><td>第三方报表相关压缩库</td></tr><tr><td>grwebapp.js</td><td>第三方报表客户端通信脚本</td></tr><tr><td>jsencrypt.js</td><td>历史封装，优先直接使用 jsencrypt 包</td></tr></tbody></table><h2 id="开发原则" tabindex="-1">开发原则 <a class="header-anchor" href="#开发原则" aria-label="Permalink to &quot;开发原则&quot;">​</a></h2><h3 id="_1-保留两套调用方式" tabindex="-1">1. 保留两套调用方式 <a class="header-anchor" href="#_1-保留两套调用方式" aria-label="Permalink to &quot;1. 保留两套调用方式&quot;">​</a></h3><p>当前约定保留两套使用方式：</p><ol><li>基座内部开发：继续使用 utils 目录下的原始文件路径，便于就近维护和调试。</li><li>子项目开发：统一从 <code>@eosine/core-sdk</code> 导入，不直接依赖 SDK 内部目录结构。</li></ol><p>推荐规则：</p><ol><li>在 core-sdk 仓库内部开发时，优先使用 <code>@/utils/...</code>。</li><li>在子项目中，优先使用 <code>@eosine/core-sdk</code>。</li><li>只要某个工具计划给子项目使用，就需要先从 SDK 入口统一导出。</li></ol><h3 id="_2-新增工具前先判断归属" tabindex="-1">2. 新增工具前先判断归属 <a class="header-anchor" href="#_2-新增工具前先判断归属" aria-label="Permalink to &quot;2. 新增工具前先判断归属&quot;">​</a></h3><p>新增 JS 方法前，先判断属于哪一类：</p><ol><li>纯前端通用函数：优先放到 index.js 或拆成单独文件。</li><li>与 store、router、request 协议耦合：放独立文件，不要塞进 index.js。</li><li>第三方库的简单转发：尽量直接依赖库，不重复造一层无意义封装。</li></ol><h3 id="_3-index-js-的边界" tabindex="-1">3. index.js 的边界 <a class="header-anchor" href="#_3-index-js-的边界" aria-label="Permalink to &quot;3. index.js 的边界&quot;">​</a></h3><p>index.js 适合放：</p><ol><li>纯函数。</li><li>无副作用方法，或副作用非常清晰的方法。</li><li>业务项目高频复用的方法。</li></ol><p>index.js 不适合放：</p><ol><li>强依赖 pinia store 的逻辑。</li><li>强依赖特定页面协议的数据拼装逻辑。</li><li>需要初始化生命周期的对象型模块。</li></ol><h3 id="_4-通用能力优先用-lodash-es" tabindex="-1">4. 通用能力优先用 lodash-es <a class="header-anchor" href="#_4-通用能力优先用-lodash-es" aria-label="Permalink to &quot;4. 通用能力优先用 lodash-es&quot;">​</a></h3><p>当前基座已接入 lodash-es。对以下类型的方法，优先直接使用 lodash-es，而不是重复手写：</p><ol><li>防抖、节流。</li><li>深拷贝。</li><li>对象合并。</li><li>数组去重。</li><li>空值过滤。</li></ol><p>当前 index.js 以下方法已统一改为调用 lodash-es：</p><ul><li>cleanArray -&gt; compact</li><li>objectMerge -&gt; merge</li><li>debounce -&gt; lodash-es debounce</li><li>deepClone -&gt; cloneDeep</li><li>uniqueArr -&gt; uniq</li></ul><p>这样做的目的：</p><ol><li>降低自实现 bug 风险。</li><li>避免多个项目维护不同版本的同类方法。</li><li>在 Vite 下可被 tree-shaking，体积可控。</li></ol>`,38)])])}const b=a(l,[["render",n]]);export{u as __pageData,b as default};
